# ════════════════════════════════════════════════════════════════════════════
#  CONSTANTS
# ════════════════════════════════════════════════════════════════════════════

SDK_NAME    = "V01D MASTER SDK"
SDK_VERSION = "0.6.1-clean"
SDK_TAGLINE = "ONE FILE. EVERY APP. FOREVER."
ENGINE_VER  = "V01D Master SDK v0.6 (clean rewrite)"

# Where this launcher lives.  Carts are read from `<here>/carts/*.json`.
HERE      = Path(__file__).resolve().parent
CARTS_DIR = HERE / "carts"

# Per-user workspace lives in your home folder so the app folder stays clean.
WORKSPACE      = Path.home() / "v01d_workspace"
SCRIPTS_DIR    = WORKSPACE / "scripts"
EXPORTS_DIR    = WORKSPACE / "exports"
USER_CARTS_DIR = WORKSPACE / "user_carts"

for folder in (WORKSPACE, SCRIPTS_DIR, EXPORTS_DIR, USER_CARTS_DIR):
    folder.mkdir(parents=True, exist_ok=True)

# CARTS_DIR is no longer required (carts are embedded below); we keep
# the constant defined in case future code wants to write there.

# Strict filename validator — no path traversal, no spaces, no dots.
SAFE_ID = re.compile(r"^[A-Za-z0-9_-]+$")


# ─── Theme colors ─────────────────────────────────────────────────────────
COLORS = {
    "bg":      "#000000",
    "panel":   "#0a0a0a",
    "ghost":   "#161616",
    "hi":      "#FFFFFF",
    "mid":     "#BBBBBB",
    "dim":     "#707070",
    "deep":    "#404040",
    "border":  "#2a2a2a",
    "accent":  "#00ff9c",
    "accent2": "#7eeaff",
    "warn":    "#ff7a4a",
    "err":     "#ff4d4d",
    "cursor":  "#FFFFFF",
}

# ─── Fonts ────────────────────────────────────────────────────────────────
FONT_FAMILY     = "Courier New"
FONT_BODY       = (FONT_FAMILY, 10)
FONT_BODY_BOLD  = (FONT_FAMILY, 10, "bold")
FONT_SMALL      = (FONT_FAMILY, 9)
FONT_TINY       = (FONT_FAMILY, 8)
FONT_HEADER     = (FONT_FAMILY, 13, "bold")
FONT_BIG_HEADER = (FONT_FAMILY, 18, "bold")
FONT_MEDIUM     = (FONT_FAMILY, 11)


# ════════════════════════════════════════════════════════════════════════════
#  CART FILE I/O
#  Each cart is one .json file containing both metadata and source code.
# ════════════════════════════════════════════════════════════════════════════

def sha256_short(data_bytes):
    """Return the first 16 hex chars of SHA-256.  Used for cart checksums."""
    return hashlib.sha256(data_bytes).hexdigest()[:16]


def cart_load(json_path):
    """
    Load a cart JSON from disk.  Returns the parsed dict with two extra
    fields added for convenience:
        _path: pathlib.Path of the JSON file we read
        _src:  the cart's source code as a string (alias of cart["source"])

    Raises ValueError if the file is malformed.
    """
    json_path = Path(json_path)
    with open(json_path, "r", encoding="utf-8") as f:
        cart = json.load(f)

    cart_id = cart.get("id", "")
    if not cart_id or not SAFE_ID.match(cart_id):
        raise ValueError(
            f"cart {json_path.name}: missing or unsafe id {cart_id!r}"
        )

    src = cart.get("source")
    if not isinstance(src, str):
        raise ValueError(
            f"cart {json_path.name}: missing 'source' string field"
        )

    cart["_path"] = json_path
    cart["_src"]  = src
    return cart


def cart_verify(cart):
    """
    Recompute the SHA-256 of the source and compare to the recorded checksum.
    Returns True if they match (or if there's no checksum to check against).
    """
    expected = cart.get("checksum")
    if not expected:
        return True
    actual = sha256_short(cart["_src"].encode("utf-8"))
    return actual == expected


def cart_save(target_dir, meta, src):
    """
    Write a cart JSON to disk.  Computes the checksum from `src`.
    Returns the path that was written.  Raises ValueError on bad input.
    """
    cart_id = meta.get("id", "")
    if not SAFE_ID.match(cart_id):
        raise ValueError(f"unsafe cart id: {cart_id!r}")

    src_bytes = src.encode("utf-8")
    cart = dict(meta)
    cart.setdefault("engine", ENGINE_VER)
    cart["source"]   = src
    cart["checksum"] = sha256_short(src_bytes)
    cart["size"]     = len(src_bytes)

    out_path = Path(target_dir) / f"{cart_id}.json"
    out_path.write_text(
        json.dumps(cart, indent=2, ensure_ascii=False),
        encoding="utf-8",
    )
    return out_path


def list_carts():
    """
    Return every cart we know about, as {cart_id: cart_dict}.

    Two sources, in this order:
        1. The 15 carts embedded at the bottom of THIS file (bundled).
        2. Any .json files in ~/v01d_workspace/user_carts/ (user-built).

    Bundled carts get `_is_user=False`; user carts get True.  On id
    collision, the user cart wins (its id is suffixed with `_user`).
    """
    found = {}

    # --- 1. Embedded bundled carts (parsed from EMBEDDED_CARTS_JSON below) ---
    try:
        bundled = json.loads(EMBEDDED_CARTS_JSON)
    except Exception as e:
        print(f"[v01d] could not parse embedded carts: {e}", file=sys.stderr)
        bundled = {}
    for cart_id, cart in bundled.items():
        if not isinstance(cart, dict):
            continue
        if not cart_id or not SAFE_ID.match(cart_id):
            continue
        src = cart.get("source")
        if not isinstance(src, str):
            continue
        # Make the same convenience fields cart_load() sets, so the rest
        # of the program treats embedded and disk carts identically.
        cart = dict(cart)
        cart["_path"]    = None        # embedded: no file path on disk
        cart["_src"]     = src
        cart["_is_user"] = False
        found[cart_id] = cart

    # --- 2. User-built carts on disk ---
    if USER_CARTS_DIR.is_dir():
        for json_path in sorted(USER_CARTS_DIR.glob("*.json")):
            try:
                cart = cart_load(json_path)
            except Exception as e:
                print(f"[v01d] skipping {json_path}: {e}", file=sys.stderr)
                continue
            cart_id = cart["id"]
            cart["_is_user"] = True
            if cart_id in found:
                cart_id = cart_id + "_user"
            found[cart_id] = cart

    return found


def run_cart_subprocess(src, on_done=None, cwd=None):
    """
    Write `src` to a temp .py file and run it as a separate Python process.
    When the process exits, on_done(returncode, output) fires from a
    background thread.  Returns the Popen handle, or None on failure.

    Why subprocess: isolation.  If the cart has a tk.mainloop or crashes,
    it doesn't take the launcher down with it.

    Why a temp file (vs. stdin): cart tracebacks point at meaningful line
    numbers instead of "<stdin>".
    """
    fd, tmp_path = tempfile.mkstemp(suffix=".py", prefix="v01d_cart_")
    try:
        with os.fdopen(fd, "w", encoding="utf-8") as f:
            f.write(src)

        proc = subprocess.Popen(
            [sys.executable, tmp_path],
            stdout=subprocess.PIPE,
            stderr=subprocess.STDOUT,
            text=True,
            cwd=str(cwd or WORKSPACE),
            # NOTE: shell=False (default).  Never set shell=True here.
        )
    except Exception as e:
        try:
            os.unlink(tmp_path)
        except OSError:
            pass
        if on_done:
            on_done(-1, str(e))
        return None

    def waiter():
        try:
            output, _ = proc.communicate()
            rc = proc.returncode
        except Exception as e:
            output, rc = str(e), -1
        try:
            os.unlink(tmp_path)
        except OSError:
            pass
        if on_done:
            on_done(rc, output or "")

    threading.Thread(target=waiter, daemon=True).start()
    return proc


# ════════════════════════════════════════════════════════════════════════════
#  TK STYLING HELPERS
# ════════════════════════════════════════════════════════════════════════════

def make_button(parent, text, command, accent=False, big=False, **extra):
    fg = COLORS["accent"] if accent else COLORS["mid"]
    pady = 6 if big else 3
    padx = 12 if big else 8
    font = FONT_BODY_BOLD if big else FONT_SMALL
    return tk.Button(
        parent, text=text, bg=COLORS["ghost"], fg=fg, font=font,
        relief="flat", bd=0, padx=padx, pady=pady,
        activebackground=COLORS["border"], activeforeground=COLORS["hi"],
        cursor="hand2", command=command, **extra,
    )


def make_text(parent, height=10, **extra):
    return tk.Text(
        parent, bg=COLORS["ghost"], fg=COLORS["hi"], font=FONT_BODY,
        insertbackground=COLORS["cursor"], relief="flat", bd=0,
        wrap="none", undo=True, maxundo=200, height=height,
        selectbackground=COLORS["accent"], selectforeground=COLORS["bg"],
        **extra,
    )


def make_listbox(parent, **extra):
    return tk.Listbox(
        parent, bg=COLORS["ghost"], fg=COLORS["hi"], font=FONT_BODY,
        selectbackground=COLORS["accent"], selectforeground=COLORS["bg"],
        relief="flat", bd=0, highlightthickness=1,
        highlightbackground=COLORS["border"], activestyle="none", **extra,
    )


def make_scrollbar(parent, **extra):
    return tk.Scrollbar(
        parent, bg=COLORS["ghost"], troughcolor=COLORS["bg"],
        bd=0, relief="flat", activebackground=COLORS["border"], **extra,
    )


def make_divider(parent, **extra):
    """Horizontal 1-pixel divider line."""
    return tk.Frame(parent, bg=COLORS["border"], height=1, **extra)


def add_clipboard_bindings(text_widget):
    """Wire up Ctrl-C/X/V/A and a right-click menu on a tk.Text widget."""
    def cut(_e=None):
        try: text_widget.event_generate("<<Cut>>")
        except tk.TclError: pass
    def copy(_e=None):
        try: text_widget.event_generate("<<Copy>>")
        except tk.TclError: pass
    def paste(_e=None):
        try: text_widget.event_generate("<<Paste>>")
        except tk.TclError: pass
    def select_all(_e=None):
        text_widget.tag_add("sel", "1.0", "end")
        return "break"

    for seq, fn in [
        ("<Control-c>", copy), ("<Control-C>", copy),
        ("<Control-x>", cut),  ("<Control-X>", cut),
        ("<Control-v>", paste),("<Control-V>", paste),
        ("<Control-a>", select_all), ("<Control-A>", select_all),
    ]:
        text_widget.bind(seq, fn)

    menu = tk.Menu(
        text_widget, tearoff=0, bg=COLORS["ghost"], fg=COLORS["hi"],
        activebackground=COLORS["border"], activeforeground=COLORS["accent"],
    )
    menu.add_command(label="Cut",        command=cut)
    menu.add_command(label="Copy",       command=copy)
    menu.add_command(label="Paste",      command=paste)
    menu.add_separator()
    menu.add_command(label="Select All", command=select_all)

    def popup(event):
        try:    menu.tk_popup(event.x_root, event.y_root)
        finally: menu.grab_release()
    text_widget.bind("<Button-3>", popup)


def open_folder_in_os(folder_path):
    """Open a folder in the host OS file manager.  No shell=True anywhere."""
    folder_str = str(folder_path)
    try:
        if sys.platform == "win32":
            os.startfile(folder_str)  # noqa: only exists on Windows
        elif sys.platform == "darwin":
            subprocess.Popen(["open", folder_str])
        else:
            subprocess.Popen(["xdg-open", folder_str])
        return True
    except Exception:
        return False


# ════════════════════════════════════════════════════════════════════════════
#  MAIN APPLICATION
# ════════════════════════════════════════════════════════════════════════════

class MasterSDK:
    """Five-tab launcher: Library, GFX Engines, IDE, Workshop, About."""

    # ── construction ─────────────────────────────────────────────────────
    def __init__(self):
        self.root = tk.Tk()
        self.root.title(f"{SDK_NAME} v{SDK_VERSION} — {SDK_TAGLINE}")
        self.root.configure(bg=COLORS["bg"])
        self.root.geometry("1280x820")
        self.root.minsize(960, 640)

        self.current_filter = "all"
        self.current_file   = None
        self.running_procs  = []
        self.search_term    = ""
        self.carts          = list_carts()

        self._build_root_chrome()
        self._build_tabs()
        self._build_status_bar()
        self._select_tab("library")
        self.root.protocol("WM_DELETE_WINDOW", self._on_close)

    def run(self):
        self.root.mainloop()

    # ── header & tab bar ─────────────────────────────────────────────────
    def _build_root_chrome(self):
        outer = tk.Frame(self.root, bg=COLORS["bg"])
        outer.pack(fill="x", padx=12, pady=(10, 0))

        title_row = tk.Frame(outer, bg=COLORS["bg"])
        title_row.pack(fill="x")
        tk.Label(title_row, text="V01D",
                 bg=COLORS["bg"], fg=COLORS["accent"],
                 font=FONT_BIG_HEADER).pack(side="left")
        tk.Label(title_row, text=" MASTER SDK ",
                 bg=COLORS["bg"], fg=COLORS["hi"],
                 font=FONT_BIG_HEADER).pack(side="left")
        tk.Label(title_row, text=f"v{SDK_VERSION}",
                 bg=COLORS["bg"], fg=COLORS["dim"],
                 font=FONT_MEDIUM).pack(side="left", pady=(8, 0))
        tk.Label(title_row, text=f"  ·  {len(self.carts)} apps",
                 bg=COLORS["bg"], fg=COLORS["accent2"],
                 font=FONT_SMALL).pack(side="left", pady=(10, 0))
        tk.Label(title_row, text=SDK_TAGLINE,
                 bg=COLORS["bg"], fg=COLORS["dim"],
                 font=FONT_SMALL).pack(side="right", pady=(10, 0))
        make_divider(outer).pack(fill="x", pady=(8, 0))

        tab_row = tk.Frame(self.root, bg=COLORS["bg"])
        tab_row.pack(fill="x", padx=12, pady=(6, 6))
        self.tab_buttons = {}
        self.tab_frames  = {}
        tabs = [
            ("library",  "📚 LIBRARY"),
            ("engines",  "🎮 GFX ENGINES"),
            ("ide",      "💻 IDE"),
            ("workshop", "📦 WORKSHOP"),
            ("about",    "ℹ ABOUT"),
        ]
        for key, label in tabs:
            btn = tk.Button(
                tab_row, text=label,
                bg=COLORS["bg"], fg=COLORS["dim"], font=FONT_BODY_BOLD,
                relief="flat", bd=0, padx=14, pady=6,
                activebackground=COLORS["bg"], activeforeground=COLORS["accent"],
                cursor="hand2",
                command=lambda k=key: self._select_tab(k),
            )
            btn.pack(side="left", padx=(0, 4))
            self.tab_buttons[key] = btn
        make_divider(self.root).pack(fill="x", padx=12)

    def _build_tabs(self):
        self.body = tk.Frame(self.root, bg=COLORS["bg"])
        self.body.pack(fill="both", expand=True, padx=12, pady=8)
        self.tab_frames["library"]  = self._build_library_tab()
        self.tab_frames["engines"]  = self._build_engines_tab()
        self.tab_frames["ide"]      = self._build_ide_tab()
        self.tab_frames["workshop"] = self._build_workshop_tab()
        self.tab_frames["about"]    = self._build_about_tab()

    def _select_tab(self, key):
        for tab_key, frame in self.tab_frames.items():
            if tab_key == key:
                frame.pack(fill="both", expand=True)
                self.tab_buttons[tab_key].config(fg=COLORS["accent"])
            else:
                frame.pack_forget()
                self.tab_buttons[tab_key].config(fg=COLORS["dim"])
        if hasattr(self, "_status_var"):
            self._status_var.set(f"[ {key.upper()} ]  ready")

    # ── status bar ───────────────────────────────────────────────────────
    def _build_status_bar(self):
        bar = tk.Frame(self.root, bg=COLORS["panel"])
        bar.pack(fill="x", side="bottom")
        make_divider(self.root).pack(fill="x", side="bottom")

        self._status_var = tk.StringVar(value="ready")
        tk.Label(bar, textvariable=self._status_var,
                 bg=COLORS["panel"], fg=COLORS["dim"],
                 font=FONT_TINY, anchor="w").pack(side="left", padx=10, pady=4)
        tk.Label(bar, text=f"workspace: {WORKSPACE}",
                 bg=COLORS["panel"], fg=COLORS["deep"],
                 font=FONT_TINY).pack(side="right", padx=10, pady=4)

    def _status(self, msg):
        if hasattr(self, "_status_var"):
            self._status_var.set(msg)

    # ─────────────────────────────────────────────────────────────────────
    #  LIBRARY TAB
    # ─────────────────────────────────────────────────────────────────────
    def _build_library_tab(self):
        frame = tk.Frame(self.body, bg=COLORS["bg"])

        toolbar = tk.Frame(frame, bg=COLORS["bg"])
        toolbar.pack(fill="x", pady=(0, 8))

        tk.Label(toolbar, text="🔍",
                 bg=COLORS["bg"], fg=COLORS["dim"],
                 font=FONT_MEDIUM).pack(side="left", padx=(0, 4))
        self.search_var = tk.StringVar()
        tk.Entry(toolbar, textvariable=self.search_var,
                 bg=COLORS["ghost"], fg=COLORS["hi"],
                 insertbackground=COLORS["cursor"], relief="flat", bd=0,
                 font=FONT_BODY, width=30,
                 ).pack(side="left", ipady=4, padx=(0, 14))
        self.search_var.trace_add("write", lambda *a: self._library_render())

        self.filter_var = tk.StringVar(value="all")
        for value, label in [
            ("all", "ALL"), ("engine", "ENGINES"), ("sdk", "SDK"),
            ("tool", "TOOLS"), ("ai", "AI"), ("creative", "CREATIVE"),
            ("game", "GAMES"), ("demo", "DEMOS"), ("user", "MY CARTS"),
        ]:
            tk.Radiobutton(
                toolbar, text=label, variable=self.filter_var, value=value,
                bg=COLORS["bg"], fg=COLORS["dim"], selectcolor=COLORS["bg"],
                activebackground=COLORS["bg"], activeforeground=COLORS["accent"],
                font=FONT_SMALL, indicatoron=0, relief="flat", bd=0,
                padx=8, pady=3, command=self._library_render,
            ).pack(side="left", padx=2)

        actions = tk.Frame(toolbar, bg=COLORS["bg"])
        actions.pack(side="right")
        make_button(actions, "↻ Refresh", self._library_refresh
                    ).pack(side="left", padx=2)
        make_button(actions, "+ Import cart", self._library_import_cart,
                    accent=True).pack(side="left", padx=2)
        make_divider(frame).pack(fill="x")

        body = tk.Frame(frame, bg=COLORS["bg"])
        body.pack(fill="both", expand=True, pady=8)
        self.lib_canvas = tk.Canvas(body, bg=COLORS["bg"],
                                    highlightthickness=0)
        self.lib_canvas.pack(side="left", fill="both", expand=True)
        sb = make_scrollbar(body, orient="vertical",
                            command=self.lib_canvas.yview)
        sb.pack(side="right", fill="y")
        self.lib_canvas.configure(yscrollcommand=sb.set)

        self.lib_inner = tk.Frame(self.lib_canvas, bg=COLORS["bg"])
        self.lib_inner_id = self.lib_canvas.create_window(
            (0, 0), window=self.lib_inner, anchor="nw",
        )

        def on_canvas_resize(event):
            self.lib_canvas.configure(scrollregion=self.lib_canvas.bbox("all"))
            self.lib_canvas.itemconfig(self.lib_inner_id, width=event.width)
        self.lib_canvas.bind("<Configure>", on_canvas_resize)
        self.lib_inner.bind("<Configure>",
            lambda e: self.lib_canvas.configure(
                scrollregion=self.lib_canvas.bbox("all")))
        self.lib_canvas.bind_all("<MouseWheel>",
            lambda event: self.lib_canvas.yview_scroll(
                int(-1 * (event.delta / 120)), "units"))
        self._library_render()
        return frame

    def _library_refresh(self):
        self.carts = list_carts()
        self._library_render()
        self._status(f"Library refreshed: {len(self.carts)} cart(s) found")

    def _library_render(self):
        for child in self.lib_inner.winfo_children():
            child.destroy()

        active_filter = (self.filter_var.get()
                         if hasattr(self, "filter_var") else "all")
        search = (self.search_var.get().lower().strip()
                  if hasattr(self, "search_var") else "")

        visible = []
        for cart_id, cart in self.carts.items():
            tag = cart.get("tag", "tool")
            is_user = cart.get("_is_user", False)
            if active_filter == "user" and not is_user:
                continue
            if active_filter not in ("all", "user") and tag != active_filter:
                continue
            if search:
                hay = " ".join([
                    cart.get("title", ""), cart.get("desc", ""),
                    cart.get("genre", ""), cart_id,
                ]).lower()
                if search not in hay:
                    continue
            visible.append((cart_id, cart))

        # Engines first (templates), then alphabetical.
        visible.sort(key=lambda kv: (
            kv[1].get("tag", "z") != "engine",
            kv[1].get("title", ""),
        ))

        columns = 3
        for index, (cart_id, cart) in enumerate(visible):
            row, col = divmod(index, columns)
            self._render_card(self.lib_inner, cart, cart_id, row, col)
        for col in range(columns):
            self.lib_inner.columnconfigure(col, weight=1, uniform="col")

        if not visible:
            tk.Label(self.lib_inner, text="(no apps match)",
                     bg=COLORS["bg"], fg=COLORS["deep"], font=FONT_BODY
                     ).grid(row=0, column=0, padx=20, pady=20)
        self._status(f"Library: {len(visible)} app(s) shown")

    def _render_card(self, parent, cart, cart_id, row, col):
        is_user = cart.get("_is_user", False)
        card = tk.Frame(parent, bg=COLORS["panel"], bd=1, relief="flat",
                        highlightthickness=1,
                        highlightbackground=COLORS["border"])
        card.grid(row=row, column=col, padx=6, pady=6, sticky="nsew",
                  ipadx=4, ipady=4)

        head = tk.Frame(card, bg=COLORS["panel"])
        head.pack(fill="x", padx=10, pady=(8, 2))
        tk.Label(head, text=cart.get("icon", "■"),
                 bg=COLORS["panel"], fg=COLORS["accent"],
                 font=(FONT_FAMILY, 18, "bold")).pack(side="left")

        title_box = tk.Frame(head, bg=COLORS["panel"])
        title_box.pack(side="left", fill="x", expand=True, padx=(8, 0))
        tk.Label(title_box, text=cart.get("title", "Untitled"),
                 bg=COLORS["panel"], fg=COLORS["hi"],
                 font=FONT_HEADER, anchor="w", justify="left",
                 ).pack(fill="x", anchor="w")
        sub = f"{cart.get('genre', '')}  ·  v{cart.get('version', '?')}"
        if is_user:
            sub = "[USER] " + sub
        tk.Label(title_box, text=sub,
                 bg=COLORS["panel"], fg=COLORS["dim"],
                 font=FONT_TINY, anchor="w").pack(fill="x", anchor="w")

        desc_text = textwrap.fill(cart.get("desc", ""), 60)
        tk.Label(card, text=desc_text,
                 bg=COLORS["panel"], fg=COLORS["mid"],
                 font=FONT_SMALL, justify="left", anchor="w",
                 wraplength=360).pack(fill="x", padx=10, pady=(2, 6))

        meta_row = tk.Frame(card, bg=COLORS["panel"])
        meta_row.pack(fill="x", padx=10, pady=(0, 6))
        kb = cart.get("size", 0) / 1024
        tk.Label(meta_row, text=f"📦 {kb:.1f} KB",
                 bg=COLORS["panel"], fg=COLORS["deep"],
                 font=FONT_TINY).pack(side="left")
        tk.Label(meta_row,
                 text=f"  ·  ✓ {cart.get('checksum', '???')[:8]}",
                 bg=COLORS["panel"], fg=COLORS["deep"],
                 font=FONT_TINY).pack(side="left")

        button_row = tk.Frame(card, bg=COLORS["panel"])
        button_row.pack(fill="x", padx=10, pady=(2, 8))
        make_button(button_row, "▶ Run",
                    lambda c=cart: self._run_cart(c), accent=True
                    ).pack(side="left", padx=2)
        make_button(button_row, "📜 Source",
                    lambda c=cart: self._view_cart_source(c)
                    ).pack(side="left", padx=2)
        make_button(button_row, "📤 Export .py",
                    lambda c=cart: self._export_cart_py(c)
                    ).pack(side="left", padx=2)

    def _run_cart(self, cart):
        title = cart.get("title", "cart")
        if not cart_verify(cart):
            answer = messagebox.askyesno(
                "Checksum mismatch",
                f"The source for '{title}' doesn't match the recorded "
                f"checksum.\n\nThis means the cart was edited since it was "
                f"registered. If you made the change yourself, this is "
                f"fine.\n\nRun anyway?",
            )
            if not answer:
                return
        self._status(f"▶ Launching {title}...")

        def on_done(rc, output):
            tail = output[-2000:] if output else ""
            self.root.after(0, lambda: self._status(
                f"[{title}] exited rc={rc}"))
            if rc != 0 and tail.strip():
                self.root.after(0,
                    lambda: self._show_error_dialog(title, rc, tail))

        proc = run_cart_subprocess(cart["_src"], on_done=on_done)
        if proc:
            self.running_procs.append(proc)

    def _show_error_dialog(self, title, rc, output):
        win = tk.Toplevel(self.root)
        win.title(f"Output — {title}")
        win.configure(bg=COLORS["bg"])
        win.geometry("760x460")
        tk.Label(win, text=f"{title} exited with code {rc}",
                 bg=COLORS["bg"], fg=COLORS["warn"], font=FONT_BODY_BOLD
                 ).pack(padx=10, pady=10, anchor="w")
        text = scrolledtext.ScrolledText(
            win, bg=COLORS["ghost"], fg=COLORS["mid"],
            font=FONT_BODY, relief="flat", bd=0,
        )
        text.pack(fill="both", expand=True, padx=10, pady=(0, 10))
        text.insert("1.0", output)
        text.configure(state="disabled")
        make_button(win, "Close", win.destroy).pack(pady=(0, 10))

    def _view_cart_source(self, cart):
        src   = cart["_src"]
        title = cart.get("title", "Source")
        win = tk.Toplevel(self.root)
        win.title(f"Source — {title}")
        win.configure(bg=COLORS["bg"])
        win.geometry("960x680")

        head = tk.Frame(win, bg=COLORS["bg"])
        head.pack(fill="x", padx=10, pady=8)
        tk.Label(head, text=f"{cart.get('icon', '■')}  {title}",
                 bg=COLORS["bg"], fg=COLORS["hi"], font=FONT_HEADER
                 ).pack(side="left")
        tk.Label(head,
                 text=(f"   {cart.get('size', 0):,} bytes  ·  "
                       f"sha256:{cart.get('checksum', '?')}"),
                 bg=COLORS["bg"], fg=COLORS["dim"], font=FONT_SMALL
                 ).pack(side="left", pady=(6, 0))

        bar = tk.Frame(win, bg=COLORS["bg"])
        bar.pack(fill="x", padx=10)

        def copy_to_clipboard():
            win.clipboard_clear()
            win.clipboard_append(src)
            self._status(f"Copied {len(src):,} bytes to clipboard")

        def open_in_ide():
            self._select_tab("ide")
            self._ide_load_text(src, name=cart.get("title", "cart") + ".py")
            win.destroy()

        def save_as():
            target = filedialog.asksaveasfilename(
                defaultextension=".py",
                initialfile=cart.get("id", "cart") + ".py",
                filetypes=[("Python", "*.py"), ("All", "*.*")],
            )
            if target:
                Path(target).write_text(src, encoding="utf-8")
                self._status(f"Saved to {target}")

        make_button(bar, "📋 Copy All", copy_to_clipboard, accent=True
                    ).pack(side="left", padx=2)
        make_button(bar, "💻 Open in IDE", open_in_ide
                    ).pack(side="left", padx=2)
        make_button(bar, "💾 Save As .py...", save_as
                    ).pack(side="left", padx=2)
        make_button(bar, "▶ Run", lambda: self._run_cart(cart)
                    ).pack(side="left", padx=2)
        make_button(bar, "Close", win.destroy
                    ).pack(side="right", padx=2)

        text_box = tk.Frame(win, bg=COLORS["bg"])
        text_box.pack(fill="both", expand=True, padx=10, pady=10)
        ysb = make_scrollbar(text_box, orient="vertical")
        ysb.pack(side="right", fill="y")
        xsb = make_scrollbar(text_box, orient="horizontal")
        xsb.pack(side="bottom", fill="x")
        viewer = make_text(text_box, height=30,
                           yscrollcommand=ysb.set, xscrollcommand=xsb.set)
        viewer.pack(fill="both", expand=True)
        ysb.config(command=viewer.yview)
        xsb.config(command=viewer.xview)
        viewer.insert("1.0", src)
        add_clipboard_bindings(viewer)

    def _export_cart_py(self, cart):
        src = cart["_src"]
        target = filedialog.asksaveasfilename(
            defaultextension=".py",
            initialdir=str(EXPORTS_DIR),
            initialfile=cart.get("id", "cart") + ".py",
            filetypes=[("Python", "*.py"), ("All", "*.*")],
        )
        if target:
            Path(target).write_text(src, encoding="utf-8")
            self._status(f"Exported {cart.get('title')} → {target}")

    def _library_import_cart(self):
        """
        Import a cart from elsewhere on disk into ~/v01d_workspace/user_carts/.
        Accepts either a cart .json (re-saved into the user folder) or a
        plain .py file (we'll generate minimal metadata for it).
        """
        path = filedialog.askopenfilename(
            title="Import cart (.py or .json)",
            initialdir=str(USER_CARTS_DIR),
            filetypes=[
                ("Cart JSON",     "*.json"),
                ("Python source", "*.py"),
                ("All",           "*.*"),
            ],
        )
        if not path:
            return
        path = Path(path)
        try:
            if path.suffix == ".json":
                cart = cart_load(path)
                cart_save(USER_CARTS_DIR, cart, cart["_src"])
                self._status(f"Imported cart {cart['id']}")
            elif path.suffix == ".py":
                stem = path.stem
                if not SAFE_ID.match(stem):
                    raise ValueError(
                        "Filename must contain only letters, digits, "
                        "underscore, or dash."
                    )
                src = path.read_text(encoding="utf-8")
                meta = {
                    "id":      stem,
                    "title":   stem.replace("_", " ").title(),
                    "author":  "imported",
                    "genre":   "User",
                    "version": "1.0",
                    "tag":     "user",
                    "icon":    "■",
                    "desc":    f"Imported from {path.name}",
                }
                cart_save(USER_CARTS_DIR, meta, src)
                self._status(f"Imported {path.name} as cart '{stem}'")
            else:
                raise ValueError("Pick a .py or .json file.")
            self._library_refresh()
            self.filter_var.set("user")
            self._library_render()
        except Exception as e:
            messagebox.showerror("Import failed", str(e))

