    def _ide_refresh(self):
        self.ide_files.delete(0, "end")
        try:
            for path in sorted(SCRIPTS_DIR.glob("*.py")):
                self.ide_files.insert("end", path.name)
        except Exception as e:
            self._status(f"refresh err: {e}")

    def _ide_on_select(self, _event=None):
        sel = self.ide_files.curselection()
        if not sel:
            return
        name = self.ide_files.get(sel[0])
        path = SCRIPTS_DIR / name
        try:
            content = path.read_text(encoding="utf-8")
            self.current_file = path
            self._ide_load_text(content, name=name, file_path=path)
        except Exception as e:
            messagebox.showerror("Error", f"Could not load: {e}")

    def _ide_load_text(self, content, name="(scratch)", file_path=None):
        self.ide_editor.delete("1.0", "end")
        self.ide_editor.insert("1.0", content)
        self.current_file = file_path
        self.ide_title_var.set(name)
        self._ide_update_counter()
        self._status(f"loaded {name}")

    def _ide_update_counter(self, _event=None):
        try:
            content = self.ide_editor.get("1.0", "end-1c")
            line_count = content.count("\n") + (1 if content else 0)
            char_count = len(content)
            self.ide_counter_var.set(
                f"{line_count} lines · {char_count:,} chars")
            self.ide_editor.edit_modified(False)
        except Exception:
            pass

    def _ide_new(self):
        name = simpledialog.askstring("New file", "Filename (.py):",
                                      parent=self.root)
        if not name:
            return
        if not name.endswith(".py"):
            name += ".py"
        if "/" in name or "\\" in name or ".." in name:
            messagebox.showerror("Bad name",
                "Filename must be a plain name with no path separators.")
            return
        target = SCRIPTS_DIR / name
        if target.exists() and not messagebox.askyesno(
            "Overwrite", f"{name} exists. Overwrite?"):
            return
        target.write_text("# new V01D script\n", encoding="utf-8")
        self._ide_refresh()
        try:
            index = list(self.ide_files.get(0, "end")).index(name)
            self.ide_files.selection_clear(0, "end")
            self.ide_files.selection_set(index)
            self.ide_files.activate(index)
            self._ide_on_select()
        except ValueError:
            pass

    def _ide_open(self):
        source = filedialog.askopenfilename(
            initialdir=str(SCRIPTS_DIR),
            filetypes=[("Python", "*.py"), ("All", "*.*")],
        )
        if not source:
            return
        try:
            content = Path(source).read_text(encoding="utf-8")
            target = SCRIPTS_DIR / Path(source).name
            if Path(source).resolve() != target.resolve():
                if target.exists() and not messagebox.askyesno(
                    "Overwrite",
                    f"{target.name} already in workspace. Overwrite?"):
                    return
                shutil.copy2(source, target)
            self.current_file = target
            self._ide_load_text(content, name=target.name, file_path=target)
            self._ide_refresh()
        except Exception as e:
            messagebox.showerror("Open failed", str(e))

    def _ide_import(self):
        source = filedialog.askopenfilename(
            title="Import .py file into workspace",
            filetypes=[("Python", "*.py"), ("All", "*.*")],
        )
        if not source:
            return
        try:
            target = SCRIPTS_DIR / Path(source).name
            if target.exists() and not messagebox.askyesno(
                "Overwrite", f"{target.name} exists. Overwrite?"):
                return
            shutil.copy2(source, target)
            self._ide_refresh()
            self._status(f"imported {target.name}")
        except Exception as e:
            messagebox.showerror("Import failed", str(e))

    def _ide_delete(self):
        if not self.current_file:
            messagebox.showinfo("Info", "No file selected")
            return
        if not messagebox.askyesno("Delete",
                                   f"Delete {self.current_file.name}?"):
            return
        try:
            self.current_file.unlink()
            self.current_file = None
            self.ide_editor.delete("1.0", "end")
            self.ide_title_var.set("(no file)")
            self._ide_refresh()
            self._status("deleted")
        except Exception as e:
            messagebox.showerror("Delete failed", str(e))

    def _ide_reveal(self):
        if not open_folder_in_os(SCRIPTS_DIR):
            messagebox.showinfo("Workspace path",
                                f"Your workspace is at:\n{SCRIPTS_DIR}")

    def _ide_save(self):
        if not self.current_file:
            name = simpledialog.askstring("Save as", "Filename (.py):",
                                          parent=self.root)
            if not name:
                return
            if not name.endswith(".py"):
                name += ".py"
            self.current_file = SCRIPTS_DIR / name
        content = self.ide_editor.get("1.0", "end-1c")
        try:
            self.current_file.write_text(content, encoding="utf-8")
            self.ide_title_var.set(self.current_file.name)
            self._ide_refresh()
            self._status(f"saved {self.current_file.name}")
        except Exception as e:
            messagebox.showerror("Save failed", str(e))

    def _ide_run(self):
        if self.current_file:
            self._ide_save()
        content = self.ide_editor.get("1.0", "end-1c").strip()
        if not content:
            self._ide_log("(empty editor)\n", err=True)
            return
        self._ide_clear_console()
        running_label = (self.current_file.name
                         if self.current_file else "<scratch>")
        self._ide_log(f"▶ Running {running_label}...\n")

        def on_done(rc, output):
            self.root.after(0, lambda: self._ide_log(output or ""))
            self.root.after(0, lambda: self._ide_log(
                f"\n[exit {rc}]\n", err=(rc != 0)))

        run_cart_subprocess(content, on_done=on_done)

    def _ide_log(self, text, err=False):
        self.ide_console.configure(state="normal")
        self.ide_console.insert("end", text)
        self.ide_console.configure(state="disabled")
        self.ide_console.see("end")

    def _ide_clear_console(self):
        self.ide_console.configure(state="normal")
        self.ide_console.delete("1.0", "end")
        self.ide_console.configure(state="disabled")

    def _ide_copy_console(self):
        try:
            content = self.ide_console.get("1.0", "end-1c")
            self.root.clipboard_clear()
            self.root.clipboard_append(content)
            self._status("console copied")
        except Exception:
            pass

    # ─────────────────────────────────────────────────────────────────────
    #  WORKSHOP TAB — wrap any source as a cart .json
    # ─────────────────────────────────────────────────────────────────────
    def _build_workshop_tab(self):
        frame = tk.Frame(self.body, bg=COLORS["bg"])

        head = tk.Frame(frame, bg=COLORS["bg"])
        head.pack(fill="x", pady=(2, 4))
        tk.Label(head, text="📦 WORKSHOP",
                 bg=COLORS["bg"], fg=COLORS["accent"], font=FONT_BIG_HEADER
                 ).pack(side="left")
        tk.Label(head,
                 text="  ·  wrap any source as a redistributable cart",
                 bg=COLORS["bg"], fg=COLORS["dim"], font=FONT_SMALL
                 ).pack(side="left", pady=(8, 0))
        make_divider(frame).pack(fill="x")

        body = tk.Frame(frame, bg=COLORS["bg"])
        body.pack(fill="both", expand=True, pady=8)

        meta_col = tk.Frame(body, bg=COLORS["bg"], width=320)
        meta_col.pack(side="left", fill="y", padx=(0, 8))
        meta_col.pack_propagate(False)

        src_col = tk.Frame(body, bg=COLORS["bg"])
        src_col.pack(side="left", fill="both", expand=True)

        tk.Label(meta_col, text="CART METADATA",
                 bg=COLORS["bg"], fg=COLORS["accent2"], font=FONT_BODY_BOLD
                 ).pack(anchor="w", pady=(0, 6))

        self.ws_fields = {}
        for key, label, default in [
            ("id",      "ID (machine name)", "my_cart"),
            ("title",   "Title",             "My Cart"),
            ("author",  "Author",            "you"),
            ("genre",   "Genre",             "Game"),
            ("version", "Version",           "1.0"),
            ("tag",     "Tag",               "tool"),
            ("icon",    "Icon (emoji)",      "■"),
        ]:
            row = tk.Frame(meta_col, bg=COLORS["bg"])
            row.pack(fill="x", pady=2)
            tk.Label(row, text=label,
                     bg=COLORS["bg"], fg=COLORS["dim"],
                     font=FONT_SMALL, width=18, anchor="w").pack(side="left")
            var = tk.StringVar(value=default)
            tk.Entry(row, textvariable=var,
                     bg=COLORS["ghost"], fg=COLORS["hi"],
                     insertbackground=COLORS["cursor"], relief="flat",
                     bd=0, font=FONT_BODY).pack(
                         side="left", fill="x", expand=True, ipady=3)
            self.ws_fields[key] = var

        tk.Label(meta_col, text="Description",
                 bg=COLORS["bg"], fg=COLORS["dim"], font=FONT_SMALL,
                 anchor="w").pack(fill="x", pady=(8, 2))
        self.ws_desc = make_text(meta_col, height=4)
        self.ws_desc.pack(fill="x")
        self.ws_desc.insert("1.0", "What this cart does...")
        add_clipboard_bindings(self.ws_desc)

        tk.Label(meta_col, text="Tag preset",
                 bg=COLORS["bg"], fg=COLORS["dim"], font=FONT_SMALL,
                 anchor="w").pack(fill="x", pady=(10, 2))
        tag_row1 = tk.Frame(meta_col, bg=COLORS["bg"]); tag_row1.pack(fill="x")
        tag_row2 = tk.Frame(meta_col, bg=COLORS["bg"]); tag_row2.pack(fill="x")
        for index, tag in enumerate(["engine", "sdk", "tool", "ai",
                                     "creative", "game", "demo"]):
            container = tag_row1 if index < 4 else tag_row2
            tk.Radiobutton(
                container, text=tag.upper(), variable=self.ws_fields["tag"],
                value=tag,
                bg=COLORS["bg"], fg=COLORS["mid"], selectcolor=COLORS["bg"],
                activebackground=COLORS["bg"], activeforeground=COLORS["accent"],
                font=FONT_TINY, indicatoron=0, bd=0, padx=4, pady=2,
            ).pack(side="left", padx=1)

        actions = tk.Frame(meta_col, bg=COLORS["bg"])
        actions.pack(fill="x", pady=(16, 4))
        make_button(actions, "📥 Load from .py...", self._ws_load_py,
                    accent=True).pack(fill="x", pady=2)
        make_button(actions, "📥 Load from cart...", self._ws_load_cart
                    ).pack(fill="x", pady=2)
        make_button(actions, "📋 Paste from clipboard", self._ws_paste
                    ).pack(fill="x", pady=2)
        make_divider(meta_col).pack(fill="x", pady=8)

        build_box = tk.Frame(meta_col, bg=COLORS["bg"])
        build_box.pack(fill="x", pady=4)
        make_button(build_box, "📦 BUILD CART", self._ws_build_cart,
                    accent=True, big=True).pack(fill="x", pady=4)
        make_button(meta_col, "🔍 PREVIEW META", self._ws_preview
                    ).pack(fill="x", pady=2)
        make_button(meta_col, "♻ Reset form", self._ws_reset
                    ).pack(fill="x", pady=2)

        tk.Label(src_col, text="SOURCE CODE",
                 bg=COLORS["bg"], fg=COLORS["accent2"], font=FONT_BODY_BOLD
                 ).pack(anchor="w", pady=(0, 6))
        src_box = tk.Frame(src_col, bg=COLORS["bg"])
        src_box.pack(fill="both", expand=True)
        ws_ysb = make_scrollbar(src_box, orient="vertical")
        ws_ysb.pack(side="right", fill="y")
        ws_xsb = make_scrollbar(src_box, orient="horizontal")
        ws_xsb.pack(side="bottom", fill="x")
        self.ws_src = make_text(src_box, height=22,
                                yscrollcommand=ws_ysb.set,
                                xscrollcommand=ws_xsb.set)
        self.ws_src.pack(fill="both", expand=True)
        ws_ysb.config(command=self.ws_src.yview)
        ws_xsb.config(command=self.ws_src.xview)
        add_clipboard_bindings(self.ws_src)
        self.ws_src.insert("1.0",
            "# Paste your Python source here, fill the metadata on the left,\n"
            "# then click 'BUILD CART' to write a single .json file in your\n"
            "# user_carts folder.\n"
            "\n"
            "import tkinter as tk\n"
            "root = tk.Tk()\n"
            "root.title('Hello from V01D')\n"
            "root.configure(bg='black')\n"
            "tk.Label(root, text='Hello world', fg='#00ff9c', bg='black',\n"
            "         font=('Courier New', 14)).pack(padx=40, pady=40)\n"
            "root.mainloop()\n"
        )

        counter_row = tk.Frame(src_col, bg=COLORS["bg"])
        counter_row.pack(fill="x", pady=4)
        self.ws_counter = tk.StringVar(value="0 bytes")
        tk.Label(counter_row, textvariable=self.ws_counter,
                 bg=COLORS["bg"], fg=COLORS["deep"], font=FONT_TINY
                 ).pack(side="left")

        def update_counter(_event=None):
            content_bytes = len(
                self.ws_src.get("1.0", "end-1c").encode("utf-8"))
            self.ws_counter.set(f"{content_bytes:,} bytes")
        self.ws_src.bind("<KeyRelease>", update_counter)
        update_counter()
        return frame

    def _ws_load_py(self):
        path = filedialog.askopenfilename(
            filetypes=[("Python", "*.py"), ("All", "*.*")])
        if not path:
            return
        try:
            content = Path(path).read_text(encoding="utf-8")
            self.ws_src.delete("1.0", "end")
            self.ws_src.insert("1.0", content)
            stem = Path(path).stem
            self.ws_fields["id"].set(stem.lower().replace(" ", "_"))
            self.ws_fields["title"].set(stem.replace("_", " "))
            self._status(f"loaded {Path(path).name} into workshop")
        except Exception as e:
            messagebox.showerror("Load failed", str(e))

    def _ws_load_cart(self):
        path = filedialog.askopenfilename(
            filetypes=[("Cart JSON", "*.json"), ("All", "*.*")])
        if not path:
            return
        try:
            cart = cart_load(path)
            self.ws_src.delete("1.0", "end")
            self.ws_src.insert("1.0", cart["_src"])
            for key, var in self.ws_fields.items():
                if key in cart:
                    var.set(str(cart[key]))
            self.ws_desc.delete("1.0", "end")
            self.ws_desc.insert("1.0", cart.get("desc", ""))
            self._status(f"loaded cart {Path(path).name}")
        except Exception as e:
            messagebox.showerror("Load failed", str(e))

    def _ws_paste(self):
        try:
            content = self.root.clipboard_get()
            self.ws_src.delete("1.0", "end")
            self.ws_src.insert("1.0", content)
            self._status(f"pasted {len(content):,} chars")
        except Exception as e:
            messagebox.showinfo("Paste",
                f"Nothing to paste, or clipboard error: {e}")

    def _ws_reset(self):
        defaults = {
            "id": "my_cart", "title": "My Cart", "author": "you",
            "genre": "Game", "version": "1.0", "tag": "tool", "icon": "■",
        }
        for key, var in self.ws_fields.items():
            var.set(defaults.get(key, ""))
        self.ws_desc.delete("1.0", "end")
        self.ws_desc.insert("1.0", "What this cart does...")
        self.ws_src.delete("1.0", "end")
        self._status("workshop reset")

    def _ws_collect_meta(self):
        meta = {key: var.get().strip()
                for key, var in self.ws_fields.items()}
        meta["desc"] = self.ws_desc.get("1.0", "end-1c").strip()
        return meta

    def _ws_preview(self):
        meta = self._ws_collect_meta()
        size = len(self.ws_src.get("1.0", "end-1c").encode("utf-8"))
        body = (
            f"ID:       {meta['id']}\n"
            f"Title:    {meta['title']}\n"
            f"Author:   {meta['author']}\n"
            f"Version:  {meta['version']}\n"
            f"Tag:      {meta['tag']}\n"
            f"Genre:    {meta['genre']}\n"
            f"Icon:     {meta['icon']}\n"
            f"Source:   {size:,} bytes\n"
            f"\n"
            f"Description:\n{meta['desc']}"
        )
        messagebox.showinfo("Cart preview", body)

    def _ws_build_cart(self):
        meta = self._ws_collect_meta()
        src  = self.ws_src.get("1.0", "end-1c")

        if not meta["id"]:
            messagebox.showerror("Missing ID", "Please set the ID field.")
            return
        if not src.strip():
            messagebox.showerror("Empty source", "Source code is empty.")
            return
        if not SAFE_ID.match(meta["id"]):
            messagebox.showerror(
                "Bad ID",
                "ID must contain only letters, digits, underscore, or dash.",
            )
            return

        try:
            json_path = cart_save(USER_CARTS_DIR, meta, src)
        except Exception as e:
            messagebox.showerror("Build failed", str(e))
            return

        self._status(f"✓ cart built: {json_path.name}")
        if messagebox.askyesno(
            "Cart saved",
            f"Saved {json_path.name}\n\nLoad in Library now?",
        ):
            self._library_refresh()
            self._select_tab("library")
            self.filter_var.set("user")
            self._library_render()

